#include <sys/wait.h>
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>

int main() {
 pid_t pid = fork();

 if (pid == -1) {
 perror("fork failed");
 exit(EXIT_FAILURE);
 }

 if (pid == 0) {
 // Child process
 printf("Child process executing\n");
 sleep(2);
 exit(42);
 } else {
 // Parent process
 int status;
 struct rusage usage;
 pid_t child_pid = wait3(&status, 0, &usage);

 if (child_pid == -1) {
 perror("wait3 failed");
 exit(EXIT_FAILURE);
 }

 if (WIFEXITED(status)) {
 printf("Child %d exited with status %d\n", child_pid, WEXITSTATUS(status));
 }

 printf("Resource usage:\n");
 printf("User CPU time: %ld.%06ld seconds\n", 
 usage.ru_utime.tv_sec, usage.ru_utime.tv_usec);
 printf("System CPU time: %ld.%06ld seconds\n",
 usage.ru_stime.tv_sec, usage.ru_stime.tv_usec);
 }
 return 0;
}

#include <sys/wait.h>
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>

int main() {
 pid_t pid = fork();

 if (pid == -1) {
 perror("fork failed");
 exit(EXIT_FAILURE);
 }

 if (pid == 0) {
 // Child process
 sleep(3);
 exit(0);
 } else {
 // Parent process
 int status;
 struct rusage usage;
 pid_t child_pid;

 do {
 child_pid = wait3(&status, WNOHANG, &usage);
 if (child_pid == 0) {
 printf("Child still running...\n");
 sleep(1);
 }
 } while (child_pid == 0);

 if (child_pid == -1) {
 perror("wait3 error");
 exit(EXIT_FAILURE);
 }

 printf("Child %d exited\n", child_pid);
 }
 return 0;
}

#include <sys/wait.h>
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>

int main() {
 for (int i = 0; i < 3; i++) {
 pid_t pid = fork();

 if (pid == -1) {
 perror("fork failed");
 exit(EXIT_FAILURE);
 }

 if (pid == 0) {
 printf("Child %d started\n", getpid());
 sleep(i + 1);
 exit(0);
 }
 }

 // Parent reaps children
 int status;
 struct rusage usage;
 pid_t child_pid;

 while ((child_pid = wait3(&status, 0, &usage)) != -1) {
 printf("Child %d exited\n", child_pid);
 }

 return 0;
}
